import{_ as a,c as t,o as r,a1 as o}from"./chunks/framework.9hXSu8bi.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/常见问题.md","filePath":"zh/帮助文档/常见问题.md"}'),l={name:"zh/帮助文档/常见问题.md"},e=o('<h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><blockquote><p>帮助用户解决使用过程中遇到的常见问题</p></blockquote><h3 id="一、账号与登录" tabindex="-1">一、账号与登录 <a class="header-anchor" href="#一、账号与登录" aria-label="Permalink to &quot;一、账号与登录&quot;">​</a></h3><ul><li><p><strong>Q: 忘记密码怎么办？</strong> A: 请联系管理员进行修改。</p></li><li><p><strong>Q: 如何修改个人资料？</strong> A: 进入用户管理界面，点击编辑。</p></li></ul><h3 id="二、项目管理" tabindex="-1">二、项目管理 <a class="header-anchor" href="#二、项目管理" aria-label="Permalink to &quot;二、项目管理&quot;">​</a></h3><ul><li><p><strong>Q: 如何新建项目？</strong> A: 在首页点击“项目”，进入项目管理页面，点击“新增”，填写项目信息并保存。具体步骤可参考“快速入门”中的第1节。</p></li><li><p><strong>Q: 项目无法删除？</strong> A: 如果项目下已添加子项目、地形数据、监测点或雷达数据，需先删除关联数据后才能删除子项目。</p></li><li><p><strong>Q: 结项后还能再编辑吗？</strong> A: 结项后的项目默认锁定，如需编辑可联系管理员重新开启。</p></li></ul><h3 id="三、地形与数据上传" tabindex="-1">三、地形与数据上传 <a class="header-anchor" href="#三、地形与数据上传" aria-label="Permalink to &quot;三、地形与数据上传&quot;">​</a></h3><ul><li><p><strong>Q: 支持哪些地形数据格式？</strong> A: 目前支持TIFF、OSGB、LAS等常见格式，具体可咨询技术支持。</p></li><li><p><strong>Q: 数据上传后显示失败？</strong> A: 请检查文件格式是否正确、网络连接是否稳定，或联系管理员查看服务器日志。</p></li><li><p><strong>Q: 地形融合需要多长时间？</strong> A: 根据数据量大小，融合时间从几秒到几分钟不等，请耐心等待。</p></li></ul><h3 id="四、地图与监测" tabindex="-1">四、地图与监测 <a class="header-anchor" href="#四、地图与监测" aria-label="Permalink to &quot;四、地图与监测&quot;">​</a></h3><ul><li><p><strong>Q: 地图加载不出来？</strong> A: 尝试刷新页面或按F5键刷新浏览器；检查网络连接；如果仍无法加载，请联系技术支持。</p></li><li><p><strong>Q: 监测点数据不更新？</strong> A: 检查雷达设备是否在线，数据上传是否正常；可尝试重新上传diff数据。</p></li><li><p><strong>Q: 如何查看形变曲线？</strong> A: 在地图上点击已创建的监测点或监测面，即可在弹出窗口中查看形变曲线。</p></li></ul><h3 id="五、预警配置" tabindex="-1">五、预警配置 <a class="header-anchor" href="#五、预警配置" aria-label="Permalink to &quot;五、预警配置&quot;">​</a></h3><ul><li><p><strong>Q: 如何设置预警策略？</strong> A: 进入“预警策略”页面，配置预警策略信息后启用。</p></li><li><p><strong>Q: 没有收到预警通知？</strong> A: 检查预警人员管理中的联系方式是否正确，确认预警数据预警通知方式，并测试邮件或短信通知功能。</p></li><li><p><strong>Q: 预警等级如何定义？</strong> A: 可在“预警配置-数据预警配置”中自定义不同等级的阈值，例如蓝色预警、黄色预警、红色预警。</p></li></ul><h3 id="六、系统与权限" tabindex="-1">六、系统与权限 <a class="header-anchor" href="#六、系统与权限" aria-label="Permalink to &quot;六、系统与权限&quot;">​</a></h3><ul><li><p><strong>Q: 如何为新用户分配权限？</strong> A: 管理员进入“角色管理”，创建或编辑角色，为角色分配相应页面授权，然后在“用户管理”中为用户配置角色。</p></li><li><p><strong>Q: 如何查看系统操作记录？</strong> A: 进入“系统日志”页面，可查看登录日志、操作日志、更新日志和预警参数变更日志，支持按日志内容、手机号、创建时间筛选。</p></li></ul><h3 id="七、其他" tabindex="-1">七、其他 <a class="header-anchor" href="#七、其他" aria-label="Permalink to &quot;七、其他&quot;">​</a></h3><ul><li><p><strong>Q: 如何联系技术支持？</strong> A: 可通过官网（www.mypattern.net）或联系电话（18547275724）获取帮助。</p></li><li><p><strong>Q: 系统有用户手册吗？</strong> A: 本帮助文档即为用户手册，涵盖了主要功能和操作指南。如有更多需求，请联系技术支持获取详细文档。</p></li></ul>',16),i=[e];function n(s,p,h,d,c,g){return r(),t("div",null,i)}const A=a(l,[["render",n]]);export{_ as __pageData,A as default};
